#include <iostream>
#include <string>
#include <vector>
#include <thread>
#include <mutex>
#include <condition_variable>

// Define the shared data structure to store account information
struct Account {
  int balance;
  std::mutex mutex;
};

// Define a vector to store all accounts
std::vector<Account> accounts;

// Define a function to update an account balance
void update_balance(int account_index, int amount) {
  // Lock the mutex for this account
  std::unique_lock<std::mutex> lock(accounts[account_index].mutex);

  // Update the account balance
  accounts[account_index].balance += amount;

  // Unlock the mutex
  lock.unlock();
}

// Define a function to read an account balance
int read_balance(int account_index) {
  // Lock the mutex for this account
  std::unique_lock<std::mutex> lock(accounts[account_index].mutex);

  // Read the account balance
  int balance = accounts[account_index].balance;

  // Unlock the mutex
  lock.unlock();

  return balance;
}

// Define a function to perform bank transactions concurrently
void bank_transactions() {
  std::vector<std::thread> threads;

  for (int i = 0; i < accounts.size(); ++i) {
    // Create a new thread for each account
    threads.push_back(std::thread([&, i] {
      // Generate a random amount to update the balance by
      int amount = std::rand() % 100;

      // Update the balance of this account
      update_balance(i, amount);
    }));
  }

  // Join all threads
  for (auto &thread : threads) {
    thread.join();
  }
}

int main() {
  // Create a vector to store all accounts
  std::vector<Account> accounts;

  // Initialize the accounts
  for (int i = 0; i < 10; ++i) {
    accounts.push_back({0, std::mutex{}});
  }

  // Perform bank transactions concurrently
  bank_transactions();

  // Print the final balances of all accounts
  for (int i = 0; i < accounts.size(); ++i) {
    std::cout << "Account " << i << ": $" << read_balance(i) << std::endl;
  }

  return 0;
}